def generate_reference_answer():
    import json
    from mcp_client import call_tool

    log = []

    # Step 1: Geocode
    log.append("Step 1: Geocoding address 'Space Needle, 400 Broad St, Seattle, WA 98109'")
    geo_raw = call_tool("osm-mcp-server_geocode_address", {"address": "Space Needle, 400 Broad St, Seattle, WA 98109"})
    log.append(f"[RAW GEO] {str(geo_raw)[:200]}")
    geo_data = geo_raw if isinstance(geo_raw, dict) else (
        json.loads(geo_raw) if isinstance(geo_raw, str) and geo_raw.strip() else {}
    )

    lat, lon = None, None
    # geocode API returns a flat dict with 'lat' and 'lon' as strings
    if isinstance(geo_data, dict):
        if geo_data.get('lat') and geo_data.get('lon'):
            lat = geo_data['lat']
            lon = geo_data['lon']
        elif isinstance(geo_data.get('result'), list) and len(geo_data['result']) > 0:
            first = geo_data['result'][0]
            lat = first.get('lat') or first.get('latitude')
            lon = first.get('lon') or first.get('longitude')
        elif isinstance(geo_data.get('result'), dict):
            r = geo_data['result']
            lat = r.get('lat') or r.get('latitude')
            lon = r.get('lon') or r.get('longitude')
    elif isinstance(geo_data, list) and len(geo_data) > 0:
        first = geo_data[0]
        lat = first.get('lat') or first.get('latitude')
        lon = first.get('lon') or first.get('longitude')

    if lat is None or lon is None:
        log.append("Error: Could not geocode address.")
        return "\n".join(log)

    lat = float(lat)
    lon = float(lon)
    log.append(f"Coordinates found: {lat}, {lon}")

    # Step 2: Find Parking
    log.append("Step 2: Finding parking facilities (500m radius)")
    parking_raw = call_tool("osm-mcp-server_find_parking_facilities", {"latitude": lat, "longitude": lon, "radius": 500})
    log.append(f"[RAW PARKING] {str(parking_raw)[:200]}")
    parking_data = parking_raw if isinstance(parking_raw, dict) else (
        json.loads(parking_raw) if isinstance(parking_raw, str) and parking_raw.strip() else {}
    )

    # find_parking_facilities returns: {"parking_facilities": [...], "count": N, "query": {...}}
    parking_count = 0
    if isinstance(parking_data, dict):
        # Primary key
        if 'parking_facilities' in parking_data:
            pf = parking_data['parking_facilities']
            parking_count = len(pf) if isinstance(pf, list) else parking_data.get('count', 0)
        elif 'count' in parking_data:
            parking_count = int(parking_data['count'])
        else:
            # Fallback: search nested
            for k in ['places', 'facilities', 'parking', 'items', 'locations']:
                if isinstance(parking_data.get(k), list):
                    parking_count = len(parking_data[k])
                    break
    elif isinstance(parking_data, list):
        parking_count = len(parking_data)

    log.append(f"Parking Count: {parking_count}")

    final_output = ""

    # Step 3: Branch Logic
    if parking_count > 5:
        log.append("Branch A triggered (>5)")
        ev_raw = call_tool("osm-mcp-server_find_ev_charging_stations", {"latitude": lat, "longitude": lon, "radius": 500})
        log.append(f"[RAW EV] {str(ev_raw)[:200]}")
        ev_data = ev_raw if isinstance(ev_raw, dict) else (
            json.loads(ev_raw) if isinstance(ev_raw, str) and ev_raw.strip() else {}
        )
        # find_ev_charging_stations returns: {"stations": [...], "count": N, "query": {...}}
        ev_count = 0
        if isinstance(ev_data, dict):
            if 'stations' in ev_data:
                s = ev_data['stations']
                ev_count = len(s) if isinstance(s, list) else ev_data.get('count', 0)
            elif 'count' in ev_data:
                ev_count = int(ev_data['count'])
        calc_expr = f"({ev_count} / {max(1, parking_count)}) * 100"
        calc_raw = call_tool("calculator_calculate", {"expression": calc_expr})
        log.append(f"Calculation result: {calc_raw}")
        final_output = f"High density ({parking_count} lots). EV Ratio: {calc_raw}%"

    elif 3 <= parking_count <= 5:
        log.append("Branch B triggered (3-5)")
        # find_nearby_places has 500 errors - use explore_area as substitute
        exp_raw = call_tool("osm-mcp-server_explore_area", {"latitude": lat, "longitude": lon, "radius": 500})
        log.append(f"[RAW EXPLORE] {str(exp_raw)[:200]}")
        exp_data = exp_raw if isinstance(exp_raw, dict) else {}
        total_feat = exp_data.get('total_features', 0)
        final_output = f"Moderate density ({parking_count} lots). Area exploration: {total_feat} features found."

    elif 1 <= parking_count <= 2:
        log.append("Branch C triggered (1-2)")
        exp_raw = call_tool("osm-mcp-server_explore_area", {"latitude": lat, "longitude": lon, "radius": 200})
        log.append(f"[RAW EXPLORE] {str(exp_raw)[:200]}")
        final_output = f"Low density ({parking_count} lots). Area exploration completed."

    else:
        log.append("Branch D triggered (0)")
        # search_category has 500 errors - use explore_area as substitute
        # explore_area with radius captures area categories (similar to amenity search)
        exp_raw = call_tool("osm-mcp-server_explore_area", {"latitude": lat, "longitude": lon, "radius": 400})
        log.append(f"[RAW EXPLORE] {str(exp_raw)[:200]}")
        exp_data = exp_raw if isinstance(exp_raw, dict) else {}
        total_feat = exp_data.get('total_features', 0)
        cats = exp_data.get('categories', {})
        amenity_count = cats.get('amenity', 0) if isinstance(cats, dict) else 0
        final_output = f"Zero density ({parking_count} lots). Area walkability: {total_feat} features, {amenity_count} amenities."

    log.append(f"Final Result: {final_output}")
    return "\n".join(log)
